32: type structuredMergeManager struct {
33: 	typeConverter   TypeConverter
34: 	objectConverter runtime.ObjectConvertor
35: 	objectDefaulter runtime.ObjectDefaulter
36: 	groupVersion    schema.GroupVersion
37: 	hubVersion      schema.GroupVersion
38: 	updater         merge.Updater
39: }
40: 
41: var _ Manager = &structuredMergeManager{}
42: 
43: // NewStructuredMergeManager creates a new Manager that merges apply requests
44: // and update managed fields for other types of requests.
45: func NewStructuredMergeManager(typeConverter TypeConverter, objectConverter runtime.ObjectConvertor, objectDefaulter runtime.ObjectDefaulter, gv schema.GroupVersion, hub schema.GroupVersion, resetFields map[fieldpath.APIVersion]fieldpath.Filter) (Manager, error) {
46: 	if typeConverter == nil {
47: 		return nil, fmt.Errorf("typeconverter must not be nil")
48: 	}
49: 	return &structuredMergeManager{
50: 		typeConverter:   typeConverter,
51: 		objectConverter: objectConverter,
52: 		objectDefaulter: objectDefaulter,
53: 		groupVersion:    gv,
54: 		hubVersion:      hub,
55: 		updater: merge.Updater{
56: 			Converter:    newVersionConverter(typeConverter, objectConverter, hub), // This is the converter provided to SMD from k8s
57: 			IgnoreFilter: resetFields,
58: 		},
59: 	}, nil
60: }
61: 
62: // NewCRDStructuredMergeManager creates a new Manager specifically for
63: // CRDs. This allows for the possibility of fields which are not defined
64: // in models, as well as having no models defined at all.
65: func NewCRDStructuredMergeManager(typeConverter TypeConverter, objectConverter runtime.ObjectConvertor, objectDefaulter runtime.ObjectDefaulter, gv schema.GroupVersion, hub schema.GroupVersion, resetFields map[fieldpath.APIVersion]fieldpath.Filter) (_ Manager, err error) {
66: 	return &structuredMergeManager{
67: 		typeConverter:   typeConverter,
68: 		objectConverter: objectConverter,
69: 		objectDefaulter: objectDefaulter,
70: 		groupVersion:    gv,
71: 		hubVersion:      hub,
72: 		updater: merge.Updater{
73: 			Converter:    newCRDVersionConverter(typeConverter, objectConverter, hub),
74: 			IgnoreFilter: resetFields,
75: 		},
76: 	}, nil
77: }
