79: func objectGVKNN(obj runtime.Object) string {
80: 	name := "<unknown>"
81: 	namespace := "<unknown>"
82: 	if accessor, err := meta.Accessor(obj); err == nil {
83: 		name = accessor.GetName()
84: 		namespace = accessor.GetNamespace()
85: 	}
86: 
87: 	return fmt.Sprintf("%v/%v; %v", namespace, name, obj.GetObjectKind().GroupVersionKind())
88: }
89: 
90: // Update implements Manager.
91: func (f *structuredMergeManager) Update(liveObj, newObj runtime.Object, managed Managed, manager string) (runtime.Object, Managed, error) {
92: 	newObjVersioned, err := f.toVersioned(newObj)
93: 	if err != nil {
94: 		return nil, nil, fmt.Errorf("failed to convert new object (%v) to proper version (%v): %v", objectGVKNN(newObj), f.groupVersion, err)
95: 	}
96: 	liveObjVersioned, err := f.toVersioned(liveObj)
97: 	if err != nil {
98: 		return nil, nil, fmt.Errorf("failed to convert live object (%v) to proper version: %v", objectGVKNN(liveObj), err)
99: 	}
100: 	newObjTyped, err := f.typeConverter.ObjectToTyped(newObjVersioned, typed.AllowDuplicates)
101: 	if err != nil {
102: 		return nil, nil, fmt.Errorf("failed to convert new object (%v) to smd typed: %v", objectGVKNN(newObjVersioned), err)
103: 	}
104: 	liveObjTyped, err := f.typeConverter.ObjectToTyped(liveObjVersioned, typed.AllowDuplicates)
105: 	if err != nil {
106: 		return nil, nil, fmt.Errorf("failed to convert live object (%v) to smd typed: %v", objectGVKNN(liveObjVersioned), err)
107: 	}
108: 	apiVersion := fieldpath.APIVersion(f.groupVersion.String())
109: 
110: 	// TODO(apelisse) use the first return value when unions are implemented
111: 	_, managedFields, err := f.updater.Update(liveObjTyped, newObjTyped, apiVersion, managed.Fields(), manager)
112: 	if err != nil {
113: 		return nil, nil, fmt.Errorf("failed to update ManagedFields (%v): %v", objectGVKNN(newObjVersioned), err)
114: 	}
115: 	managed = NewManaged(managedFields, managed.Times())
116: 
117: 	return newObj, managed, nil
118: }
119: 
120: // Apply implements Manager.
121: func (f *structuredMergeManager) Apply(liveObj, patchObj runtime.Object, managed Managed, manager string, force bool) (runtime.Object, Managed, error) {
122: 	// Check that the patch object has the same version as the live object
123: 	if patchVersion := patchObj.GetObjectKind().GroupVersionKind().GroupVersion(); patchVersion != f.groupVersion {
124: 		return nil, nil,
125: 			errors.NewBadRequest(
126: 				fmt.Sprintf("Incorrect version specified in apply patch. "+
127: 					"Specified patch version: %s, expected: %s",
128: 					patchVersion, f.groupVersion))
129: 	}
130: 
131: 	patchObjMeta, err := meta.Accessor(patchObj)
132: 	if err != nil {
133: 		return nil, nil, fmt.Errorf("couldn't get accessor: %v", err)
134: 	}
135: 	if patchObjMeta.GetManagedFields() != nil {
136: 		return nil, nil, errors.NewBadRequest("metadata.managedFields must be nil")
137: 	}
138: 
139: 	liveObjVersioned, err := f.toVersioned(liveObj)
140: 	if err != nil {
141: 		return nil, nil, fmt.Errorf("failed to convert live object (%v) to proper version: %v", objectGVKNN(liveObj), err)
142: 	}
143: 
144: 	// Don't allow duplicates in the applied object.
145: 	patchObjTyped, err := f.typeConverter.ObjectToTyped(patchObj)
146: 	if err != nil {
147: 		return nil, nil, fmt.Errorf("failed to create typed patch object (%v): %v", objectGVKNN(patchObj), err)
148: 	}
149: 
150: 	liveObjTyped, err := f.typeConverter.ObjectToTyped(liveObjVersioned, typed.AllowDuplicates)
151: 	if err != nil {
152: 		return nil, nil, fmt.Errorf("failed to create typed live object (%v): %v", objectGVKNN(liveObjVersioned), err)
153: 	}
154: 
155: 	apiVersion := fieldpath.APIVersion(f.groupVersion.String())
156: 	newObjTyped, managedFields, err := f.updater.Apply(liveObjTyped, patchObjTyped, apiVersion, managed.Fields(), manager, force)
157: 	if err != nil {
158: 		return nil, nil, err
159: 	}
160: 	managed = NewManaged(managedFields, managed.Times())
161: 
162: 	if newObjTyped == nil {
163: 		return nil, managed, nil
164: 	}
165: 
166: 	newObj, err := f.typeConverter.TypedToObject(newObjTyped)
167: 	if err != nil {
168: 		return nil, nil, fmt.Errorf("failed to convert new typed object (%v) to object: %v", objectGVKNN(patchObj), err)
169: 	}
170: 
171: 	newObjVersioned, err := f.toVersioned(newObj)
172: 	if err != nil {
173: 		return nil, nil, fmt.Errorf("failed to convert new object (%v) to proper version: %v", objectGVKNN(patchObj), err)
174: 	}
175: 	f.objectDefaulter.Default(newObjVersioned)
176: 
177: 	newObjUnversioned, err := f.toUnversioned(newObjVersioned)
178: 	if err != nil {
179: 		return nil, nil, fmt.Errorf("failed to convert to unversioned (%v): %v", objectGVKNN(patchObj), err)
180: 	}
181: 	return newObjUnversioned, managed, nil
182: }
183: 
184: func (f *structuredMergeManager) toVersioned(obj runtime.Object) (runtime.Object, error) {
185: 	return f.objectConverter.ConvertToVersion(obj, f.groupVersion)
186: }
187: 
188: func (f *structuredMergeManager) toUnversioned(obj runtime.Object) (runtime.Object, error) {
189: 	return f.objectConverter.ConvertToVersion(obj, f.hubVersion)
190: }
